-- Item Fragment Management functions

-- extract_fragment: Given full STAC item JSONB and a list of serialized fragment paths
-- (each element is fragment_path_text(text[]) — a JSON-array serialized root-relative path),
-- extract the sparse overlay JSONB that will be stored in item_fragments for dedup.
-- Returns NULL when fragment_paths is NULL or empty, or when no values are found.
-- Supports paths at any depth:
--   depth-1  (e.g. 'stac_version')                  → extracts the whole top-level key.
--   depth-2  (e.g. 'assets.thumbnail')               → extracts a named sub-key.
--   depth-3+ (e.g. 'assets.thumbnail.type')          → extracts a nested sub-sub-key,
--                                                       building a sparse nested JSONB.
-- Multiple paths sharing intermediate keys are merged correctly so that, for example,
-- 'assets.thumbnail.type' and 'assets.thumbnail.roles' together produce
-- {"assets": {"thumbnail": {"type": ..., "roles": ...}}} rather than overwriting.
CREATE OR REPLACE FUNCTION extract_fragment(
    content jsonb,
    fragment_paths text[]
) RETURNS jsonb AS $$
DECLARE
    result    jsonb := '{}'::jsonb;
    p         text;
    pth       text[];
    val       jsonb;
BEGIN
    IF content IS NULL OR fragment_paths IS NULL OR cardinality(fragment_paths) = 0 THEN
        RETURN NULL;
    END IF;

    FOREACH p IN ARRAY fragment_paths LOOP
        pth := fragment_path_array(p);
        IF pth IS NULL OR cardinality(pth) = 0 THEN CONTINUE; END IF;

        val := content #> pth;
        IF val IS NOT NULL THEN
            -- jsonb_set_nested creates intermediate empty objects as needed, so
            -- depth-3+ paths are handled correctly and multiple paths sharing the
            -- same intermediate keys are merged rather than overwritten.
            result := jsonb_set_nested(result, pth, val);
        END IF;
    END LOOP;

    IF result = '{}'::jsonb THEN RETURN NULL; END IF;
    RETURN result;
END;
$$ LANGUAGE PLPGSQL IMMUTABLE PARALLEL SAFE;

-- pgstac_hash_fragment: Hash a fragment payload for dedup. Returns the raw
-- 32-byte sha256 (bytea), stored directly in item_fragments.hash. The fragment
-- jsonb is normalized to a single canonical text by PostgreSQL (equal fragments
-- always serialize identically), so jsonb::text is sufficient for this
-- internal dedup key; the externally reproducible item digest is pgstac_item_hash.
CREATE OR REPLACE FUNCTION pgstac_hash_fragment(fragment jsonb) RETURNS bytea AS $$
SELECT sha256(convert_to(fragment::text, 'UTF8'));
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;


-- strip_fragment_col: Remove fragment-owned sub-keys from a split column value.
-- col_name is the top-level STAC key that this column represents (e.g. 'assets' or 'properties').
-- fragment_paths is the collection's fragment_config text[].
-- Supports paths at any depth:
--   depth-1  matching col_name  → zeroes out the entire column (returns '{}').
--   depth-2+ matching col_name  → removes the nested sub-path using the #- operator,
--                                  which handles arbitrary nesting without requiring a loop.
-- Examples with col_name='assets':
--   'assets'                  → returns '{}'  (whole column is in the fragment)
--   'assets.thumbnail'        → removes 'thumbnail' key  (depth-2, old behaviour)
--   'assets.thumbnail.type'   → removes 'type' from within 'thumbnail'  (depth-3, new)
-- Returns col_value unchanged when there are no matching fragment paths.
CREATE OR REPLACE FUNCTION strip_fragment_col(
    col_value jsonb,
    col_name  text,
    fragment_paths text[]
) RETURNS jsonb AS $$
DECLARE
    result    jsonb := col_value;
    p         text;
    pth       text[];
    n         int;
BEGIN
    IF col_value IS NULL OR fragment_paths IS NULL THEN RETURN col_value; END IF;

    FOREACH p IN ARRAY fragment_paths LOOP
        pth := fragment_path_array(p);
        n   := cardinality(pth);
        IF pth IS NULL OR n = 0 OR pth[1] <> col_name THEN CONTINUE; END IF;

        IF n = 1 THEN
            RETURN '{}'::jsonb;  -- entire column goes to fragment
        ELSE
            -- Remove the nested sub-path from the column value at any depth.
            -- #- handles depth-2 (removes a top-level key) through depth-N (removes a
            -- nested key) using the path tail pth[2:n].
            result := result #- pth[2:n];
        END IF;
    END LOOP;

    RETURN result;
END;
$$ LANGUAGE PLPGSQL IMMUTABLE PARALLEL SAFE;
-- END FRAGMENT: 003a_items.sql

-- BEGIN FRAGMENT: 003b_partitions.sql
CREATE TABLE partition_stats (
    partition text PRIMARY KEY,
    collection text,
    -- dtrange/edtrange are the data bounds used for search pruning. widen_partition_stats fills them
    -- (generously) on ingest; tighten_partition_stats narrows them to the exact extent. The partition's
    -- structural range lives in its own constraint, read via partitions_view.constraint_dtrange.
    dtrange tstzrange,
    edtrange tstzrange,
    spatial geometry,
    last_updated timestamptz,
    n bigint,
    -- Deferred-maintenance flags:
    --   dirty:           the stored envelope may be WIDER than the actual data; an async tightener
    --                    should recompute exact min/max/extent and clear the flag. Search correctness
    --                    never depends on this (a wide envelope only over-includes a partition).
    --   indexes_pending: the partition currently carries only the parent-inherited indexes (id PK,
    --                    datetime, geometry); its queryable-defined indexes have not been built yet.
    dirty boolean NOT NULL DEFAULT false,
    indexes_pending boolean NOT NULL DEFAULT false
) WITH (FILLFACTOR=70);

CREATE INDEX partitions_range_idx ON partition_stats USING GIST(dtrange);
CREATE INDEX partition_stats_collection_idx ON partition_stats (collection);
CREATE INDEX partition_stats_spatial_idx ON partition_stats USING GIST(spatial) WHERE spatial IS NOT NULL;
-- Work-queue indexes: the maintenance sweeps find pending partitions without scanning every row.
CREATE INDEX partition_stats_dirty_idx ON partition_stats (partition) WHERE dirty;
CREATE INDEX partition_stats_indexes_pending_idx ON partition_stats (partition) WHERE indexes_pending;


CREATE OR REPLACE FUNCTION constraint_tstzrange(expr text) RETURNS tstzrange AS $$
    WITH t AS (
        SELECT regexp_matches(
            expr,
            E'\\(''\([0-9 :+-]*\)''\\).*\\(''\([0-9 :+-]*\)''\\)'
        ) AS m
    ) SELECT tstzrange(m[1]::timestamptz, m[2]::timestamptz) FROM t
    ;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE STRICT;

CREATE OR REPLACE FUNCTION get_tstz_constraint(reloid oid, colname text) RETURNS tstzrange AS $$
DECLARE
    expr text := NULL;
    m text[];
    ts_lower timestamptz := NULL;
    ts_upper timestamptz := NULL;
    lower_inclusive text := '[';
    upper_inclusive text := ']';
    ts timestamptz;
BEGIN
    SELECT INTO expr
        string_agg(def, ' AND ')
    FROM pg_constraint JOIN LATERAL pg_get_constraintdef(oid) AS def ON TRUE
    WHERE
        conrelid = reloid
        AND contype = 'c'
        AND def LIKE '%' || colname || '%'
    ;

    IF expr IS NULL THEN
        RETURN NULL;
    END IF;

    RAISE DEBUG 'Constraint expression for % on %: %', colname, reloid::regclass, expr;
    -- collect all constraints for the specified column
    FOR m IN SELECT regexp_matches(expr, '[ (]' || colname || $expr$\s*([<>=]{1,2})\s*'([0-9 :.+\-]+)'$expr$, 'g') LOOP
        ts := m[2]::timestamptz;
        IF m[1] IN ('>', '>=')
        THEN
            IF ts_lower IS NULL OR ts > ts_lower OR (ts = ts_lower AND m[1] = '>') THEN
                ts_lower := ts;
                lower_inclusive := CASE WHEN m[1] = '>' THEN '(' ELSE '[' END;
            END IF;
        ELSIF m[1] IN ('<', '<=')
        THEN
            IF ts_upper IS NULL OR ts < ts_upper OR (ts = ts_upper AND m[1] = '<') THEN
                ts_upper := ts;
                upper_inclusive := CASE WHEN m[1] = '<' THEN ')' ELSE ']' END;
            END IF;
        END IF;
    END LOOP;
    RAISE DEBUG 'Constraint % for %: % %', colname, reloid::regclass, ts_lower, ts_upper;
    RETURN tstzrange(ts_lower, ts_upper, lower_inclusive || upper_inclusive);
END;
$$ LANGUAGE plpgsql STRICT STABLE;

CREATE OR REPLACE FUNCTION get_partition_name(relid regclass) RETURNS text AS $$
    SELECT (parse_ident(relid::text))[cardinality(parse_ident(relid::text))];
$$ LANGUAGE SQL STABLE STRICT;

CREATE OR REPLACE VIEW partition_sys_meta AS
SELECT
    partition,
    replace(
        replace(
            CASE WHEN level = 1 THEN partition_expr ELSE parent_partition_expr END,
            'FOR VALUES IN (''',
            ''
        ),
        ''')',
        ''
    ) AS collection,
    level,
    c.reltuples,
    c.relhastriggers,
    COALESCE(
        get_tstz_constraint(c.oid, 'datetime'),
        constraint_tstzrange(pg_get_expr(c.relpartbound, c.oid)),
        inf_range
    ) as constraint_dtrange,
    COALESCE(
        get_tstz_constraint(c.oid, 'end_datetime'),
        inf_range
    ) as constraint_edtrange
FROM
    pg_partition_tree('items')
    JOIN pg_class c ON (relid::regclass = c.oid)
    JOIN pg_class parent ON (parentrelid::regclass = parent.oid AND isleaf)
    LEFT JOIN pg_constraint edt ON (conrelid=c.oid AND contype='c')
    JOIN LATERAL get_partition_name(relid) AS partition ON TRUE
    JOIN LATERAL pg_get_expr(c.relpartbound, c.oid) as partition_expr ON TRUE
    JOIN LATERAL pg_get_expr(parent.relpartbound, parent.oid) as parent_partition_expr ON TRUE
    JOIN LATERAL tstzrange('-infinity', 'infinity','[]') as inf_range ON TRUE
    JOIN LATERAL get_tstz_constraint(c.oid, 'datetime') as datetime_constraint ON TRUE
    JOIN LATERAL get_tstz_constraint(c.oid, 'end_datetime') as end_datetime_constraint ON TRUE
WHERE isleaf
;

CREATE OR REPLACE VIEW partitions_view AS
SELECT
    (parse_ident(relid::text))[cardinality(parse_ident(relid::text))] as partition,
    replace(
        replace(
            CASE WHEN level = 1 THEN partition_expr ELSE parent_partition_expr END,
            'FOR VALUES IN (''',
            ''
        ),
        ''')',
        ''
    ) AS collection,
    level,
    c.reltuples,
    c.relhastriggers,
    COALESCE(
        get_tstz_constraint(c.oid, 'datetime'),
        constraint_tstzrange(pg_get_expr(c.relpartbound, c.oid)),
        inf_range
    ) as constraint_dtrange,
    COALESCE(
        get_tstz_constraint(c.oid, 'end_datetime'),
        inf_range
    ) as constraint_edtrange,
    dtrange,
    edtrange,
    spatial,
    last_updated
FROM
    pg_partition_tree('items')
    JOIN pg_class c ON (relid::regclass = c.oid)
    JOIN pg_class parent ON (parentrelid::regclass = parent.oid AND isleaf)
    LEFT JOIN pg_constraint edt ON (conrelid=c.oid AND contype='c')
    JOIN LATERAL get_partition_name(relid) AS partition ON TRUE
    JOIN LATERAL pg_get_expr(c.relpartbound, c.oid) as partition_expr ON TRUE
    JOIN LATERAL pg_get_expr(parent.relpartbound, parent.oid) as parent_partition_expr ON TRUE
    JOIN LATERAL tstzrange('-infinity', 'infinity','[]') as inf_range ON TRUE
    JOIN LATERAL get_tstz_constraint(c.oid, 'datetime') as datetime_constraint ON TRUE
    JOIN LATERAL get_tstz_constraint(c.oid, 'end_datetime') as end_datetime_constraint ON TRUE
    -- the view computes its own collection + constraint_dtrange from the live tree; pull only the
    -- data-extent columns from partition_stats to avoid colliding with those names.
    LEFT JOIN (
        SELECT partition, dtrange, edtrange, spatial, last_updated
        FROM pgstac.partition_stats
    ) ps USING (partition)
WHERE isleaf
;



CREATE OR REPLACE FUNCTION partition_name( IN collection text, IN dt timestamptz, OUT partition_name text, OUT partition_range tstzrange) AS $$
DECLARE
    c RECORD;
    parent_name text;
BEGIN
    SELECT * INTO c FROM pgstac.collections WHERE id=collection;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Collection % does not exist', collection USING ERRCODE = 'foreign_key_violation', HINT = 'Make sure collection exists before adding items';
    END IF;
    parent_name := format('_items_%s', c.key);


    IF c.partition_trunc = 'year' THEN
        partition_name := format('%s_%s', parent_name, to_char(dt,'YYYY'));
    ELSIF c.partition_trunc = 'month' THEN
        partition_name := format('%s_%s', parent_name, to_char(dt,'YYYYMM'));
    ELSE
        partition_name := parent_name;
        partition_range := tstzrange('-infinity'::timestamptz, 'infinity'::timestamptz, '[]');
    END IF;
    IF partition_range IS NULL THEN
        partition_range := tstzrange(
            date_trunc(c.partition_trunc::text, dt),
            date_trunc(c.partition_trunc::text, dt) + concat('1 ', c.partition_trunc)::interval
        );
    END IF;
    RETURN;

END;
$$ LANGUAGE PLPGSQL STABLE;


-- Partitions carry no _dt CHECK constraints; pruning is partition_stats-driven. get_tstz_constraint /
-- constraint_tstzrange remain so the views' constraint_* columns resolve to inf_range when a partition
-- has no datetime constraint.


-- widen_partition_stats: widen a partition's stored envelope to cover a batch. A no-op (snapshot read, no
-- write, no lock) when the envelope already covers the batch; otherwise widens and sets dirty=true:
--   * datetime    : sub-partitioned collections widen to the partition's datetime bound (covers anything
--                   that can land there); a NULL-partition_trunc partition pads the batch range by
--                   partition_stats_widen_buffer (default 1 month) each side.
--   * end_datetime: the datetime target extended by the batch's max (end_datetime - datetime) tail.
--   * spatial     : NULL means "always a search candidate"; a spatial miss resets spatial to NULL until
--                   the tightener computes the real extent.
-- Requires the partition_stats row to exist (check_partition seeds it); raises if it does not.
CREATE OR REPLACE FUNCTION widen_partition_stats(
    _partition text,
    _dtrange tstzrange,
    _edtrange tstzrange,
    _spatial geometry DEFAULT NULL,
    _constraint_dtrange tstzrange DEFAULT NULL
) RETURNS void AS $$
DECLARE
    cur RECORD;
    is_unbounded boolean;
    tail interval;
    buf interval := COALESCE(get_setting('partition_stats_widen_buffer'), '1 month')::interval;
    target_dtrange tstzrange;
    target_edtrange tstzrange;
    new_dtrange tstzrange;
    new_edtrange tstzrange;
    new_spatial geometry;
    dt_covered boolean;
    edt_covered boolean;
    spatial_covered boolean;
BEGIN
    SELECT dtrange, edtrange, spatial
        INTO cur
        FROM partition_stats WHERE partition = _partition;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'partition_stats row for % does not exist; call check_partition first', _partition;
    END IF;

    dt_covered  := COALESCE(cur.dtrange  @> _dtrange,  false);
    edt_covered := COALESCE(cur.edtrange @> _edtrange, false);
    spatial_covered := cur.spatial IS NULL OR _spatial IS NULL OR ST_Covers(cur.spatial, _spatial);
    IF dt_covered AND edt_covered AND spatial_covered THEN
        RETURN; -- already covered: no write, no lock
    END IF;

    -- Clamp the widen to the partition's structural bound (_constraint_dtrange). A sub-partitioned
    -- (month/year) partition's bound is finite: cover the whole partition so dtrange never misses and
    -- never spills into a neighbour. An unbounded partition (NULL-partition_trunc or NULL bound) has
    -- nothing to clamp to, so pad the batch range by the widen buffer each side.
    is_unbounded := _constraint_dtrange IS NULL
                 OR (lower(_constraint_dtrange) = '-infinity'::timestamptz
                     AND upper(_constraint_dtrange) = 'infinity'::timestamptz);
    tail := GREATEST(upper(_edtrange) - upper(_dtrange), '0'::interval);
    IF is_unbounded THEN
        target_dtrange  := tstzrange(lower(_dtrange) - buf, upper(_dtrange) + buf, '[]');
        target_edtrange := tstzrange(lower(_dtrange) - buf, upper(_edtrange) + buf, '[]');
    ELSE
        target_dtrange  := _constraint_dtrange;
        target_edtrange := tstzrange(lower(_constraint_dtrange), upper(_constraint_dtrange) + tail, '[]');
    END IF;

    new_dtrange  := range_merge(COALESCE(cur.dtrange,  target_dtrange),  target_dtrange);
    new_edtrange := range_merge(COALESCE(cur.edtrange, target_edtrange), target_edtrange);
    new_spatial  := CASE WHEN spatial_covered THEN cur.spatial ELSE NULL END;

    UPDATE partition_stats
        SET dtrange = new_dtrange,
            edtrange = new_edtrange,
            spatial = new_spatial,
            dirty = true,
            last_updated = now()
        WHERE partition = _partition;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;


CREATE OR REPLACE FUNCTION check_partition(
    _collection text,
    _dtrange tstzrange,
    _edtrange tstzrange,
    _spatial geometry DEFAULT NULL
) RETURNS text AS $$
DECLARE
    c RECORD;
    _partition_name text;
    _parent_name text;
    _partition_range tstzrange;
BEGIN
    SELECT * INTO c FROM pgstac.collections WHERE id=_collection;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Collection % does not exist', _collection USING ERRCODE = 'foreign_key_violation', HINT = 'Make sure collection exists before adding items';
    END IF;

    IF c.partition_trunc IS NOT NULL THEN
        _partition_range := tstzrange(
            date_trunc(c.partition_trunc, lower(_dtrange)),
            date_trunc(c.partition_trunc, lower(_dtrange)) + (concat('1 ', c.partition_trunc))::interval,
            '[)'
        );
    ELSE
        _partition_range := '[-infinity, infinity]'::tstzrange;
    END IF;

    IF NOT _partition_range @> _dtrange THEN
        RAISE EXCEPTION 'dtrange % spans more than the % partition window for collection %', _dtrange, c.partition_trunc, _collection;
    END IF;

    _parent_name := format('_items_%s', c.key);
    IF c.partition_trunc = 'year' THEN
        _partition_name := format('%s_%s', _parent_name, to_char(lower(_partition_range),'YYYY'));
    ELSIF c.partition_trunc = 'month' THEN
        _partition_name := format('%s_%s', _parent_name, to_char(lower(_partition_range),'YYYYMM'));
    ELSE
        _partition_name := _parent_name;
    END IF;

    -- Create the collection-level PARENT partition (_items_<key>) first, for sub-partitioned collections.
    -- It is shared across every child window, so concurrent setup of different children would race on its
    -- CREATE TABLE. Guard it with a parent-scoped advisory lock, taken before any child lock and only when
    -- the parent is missing: parent-before-child is one lock order (parent < child) that can't deadlock
    -- with ensure_partitions' sorted child locks, and skipping it once the parent exists keeps steady-state
    -- ingest off the parent lock.
    IF c.partition_trunc IS NOT NULL AND to_regclass(format('pgstac.%I', _parent_name)) IS NULL THEN
        PERFORM pg_advisory_xact_lock(hashtext('pgstac.check_partition'), hashtext(_parent_name));
        IF to_regclass(format('pgstac.%I', _parent_name)) IS NULL THEN
            EXECUTE format(
                'CREATE TABLE IF NOT EXISTS %I partition OF items FOR VALUES IN (%L) PARTITION BY RANGE (datetime)',
                _parent_name, _collection
            );
        END IF;
    END IF;

    -- Serialize concurrent setup of THIS (leaf) partition with a partition-scoped advisory lock. Different
    -- partitions hash to different keys, so this never serializes unrelated ingest; ensure_partitions
    -- acquires these in sorted order, so concurrent multi-partition batches cannot deadlock. The lock
    -- releases at commit (setup is fast + idempotent).
    PERFORM pg_advisory_xact_lock(hashtext('pgstac.check_partition'), hashtext(_partition_name));

    -- Create the leaf partition if missing. Parent-inherited indexes only (id PK here; datetime/geometry
    -- come from the items parent); no CHECK constraints; queryable indexes are deferred via
    -- indexes_pending. A SELECT grant lets read/ingest query it; writes reach it only through the
    -- SECURITY DEFINER write functions (the privilege wall in 998_idempotent_post).
    -- Skip the DDL when it already exists: re-running CREATE/GRANT takes a relation lock that deadlocks
    -- with concurrent INSERTs. The existence check is race-safe under the advisory lock.
    IF to_regclass(format('pgstac.%I', _partition_name)) IS NULL THEN
        BEGIN
            IF c.partition_trunc IS NULL THEN
                EXECUTE format(
                    $q$
                        CREATE TABLE IF NOT EXISTS %I partition OF items FOR VALUES IN (%L);
                        CREATE UNIQUE INDEX IF NOT EXISTS %I ON %I (id);
                        GRANT SELECT ON %I TO pgstac_read, pgstac_ingest;
                    $q$,
                    _partition_name, _collection,
                    concat(_partition_name, '_pk'), _partition_name,
                    _partition_name
                );
            ELSE
                EXECUTE format(
                    $q$
                        CREATE TABLE IF NOT EXISTS %I partition OF %I FOR VALUES FROM (%L) TO (%L);
                        CREATE UNIQUE INDEX IF NOT EXISTS %I ON %I (id);
                        GRANT SELECT ON %I TO pgstac_read, pgstac_ingest;
                    $q$,
                    _partition_name, _parent_name, lower(_partition_range), upper(_partition_range),
                    concat(_partition_name, '_pk'), _partition_name,
                    _partition_name
                );
            END IF;
        EXCEPTION
            -- A concurrent creator that finished between our checks: benign, it exists now.
            WHEN duplicate_table THEN
                RAISE DEBUG 'Partition % already exists.', _partition_name;
            -- Do NOT swallow other errors: a failed creation must propagate so the caller never goes on to
            -- write a partition that does not exist (invariant: check_partition succeeds before use).
        END;
    END IF;

    -- Seed the partition_stats row (collection only — the data ranges start NULL), then cover this batch
    -- via the shared widen guard, which fills dtrange/edtrange. ON CONFLICT keeps an existing row (so a
    -- sweep that cleared indexes_pending/dirty is not reset on a later check_partition for the same
    -- partition).
    INSERT INTO partition_stats (partition, collection, dirty, indexes_pending)
        VALUES (_partition_name, _collection, true, true)
        ON CONFLICT (partition) DO NOTHING;
    PERFORM widen_partition_stats(_partition_name, _dtrange, _edtrange, _spatial, _partition_range);

    RETURN _partition_name;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;


CREATE OR REPLACE FUNCTION repartition(_collection text, _partition_trunc text, triggered boolean DEFAULT FALSE) RETURNS text AS $$
DECLARE
    c RECORD;
    q text;
    from_trunc text;
BEGIN
    SELECT * INTO c FROM pgstac.collections WHERE id=_collection;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Collection % does not exist', _collection USING ERRCODE = 'foreign_key_violation', HINT = 'Make sure collection exists before adding items';
    END IF;
    IF triggered THEN
        RAISE NOTICE 'Converting % to % partitioning via Trigger', _collection, _partition_trunc;
    ELSE
        RAISE NOTICE 'Converting % from using % to % partitioning', _collection, c.partition_trunc, _partition_trunc;
        IF c.partition_trunc IS NOT DISTINCT FROM _partition_trunc THEN
            RAISE NOTICE 'Collection % already set to use partition by %', _collection, _partition_trunc;
            RETURN _collection;
        END IF;
    END IF;

    IF EXISTS (SELECT 1 FROM partitions_view WHERE collection=_collection LIMIT 1) THEN
        EXECUTE format(
            $q$
                CREATE TEMP TABLE changepartitionstaging ON COMMIT DROP AS SELECT * FROM %I;
                DROP TABLE IF EXISTS %I CASCADE;
                WITH p AS (
                    SELECT
                        collection,
                        CASE
                            WHEN %L IS NULL THEN '-infinity'::timestamptz
                            ELSE date_trunc(%L, datetime)
                        END as d,
                        tstzrange(min(datetime),max(datetime),'[]') as dtrange,
                        tstzrange(min(end_datetime),max(end_datetime),'[]') as edtrange
                    FROM changepartitionstaging
                    GROUP BY 1,2
                ) SELECT check_partition(collection, dtrange, edtrange) FROM p;
                INSERT INTO items SELECT * FROM changepartitionstaging;
                DROP TABLE changepartitionstaging;
            $q$,
            concat('_items_', c.key),
            concat('_items_', c.key),
            c.partition_trunc,
            c.partition_trunc
        );
    END IF;
    RETURN _collection;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION collections_trigger_func() RETURNS TRIGGER AS $$
DECLARE
    q text;
    partition_name text := format('_items_%s', NEW.key);
    partition_exists boolean := false;
    partition_empty boolean := true;
    err_context text;
    loadtemp boolean := FALSE;
BEGIN
    RAISE NOTICE 'Collection Trigger. % %', NEW.id, NEW.key;
    IF TG_OP = 'UPDATE' AND NEW.partition_trunc IS DISTINCT FROM OLD.partition_trunc THEN
        PERFORM repartition(NEW.id, NEW.partition_trunc, TRUE);
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE PLPGSQL;


CREATE TRIGGER collections_trigger AFTER
INSERT
OR
UPDATE ON collections
FOR EACH ROW EXECUTE FUNCTION collections_trigger_func();
-- END FRAGMENT: 003b_partitions.sql

-- BEGIN FRAGMENT: 003c_ingest.sql
-- ---------------------------------------------------------------------------
-- Rust-first ingest: SECURITY DEFINER staging + flush + fragment helpers.
--
-- These are the server-side seam for the Rust loader's binary-COPY path. The connecting role never
-- writes the real tables directly; it binary-COPYs fully-dehydrated rows into a session-local TEMP
-- table (make_binary_staging) and calls flush_items_staging_binary, which is the only thing that writes
-- `items`. Partition existence + stats (extent + n) and registry/fragment coverage are established BEFORE
-- the load in their own transactions (prepare_partition_for_load / ensure_fragments); the flush writes only
-- `items` and never touches partition_stats.
-- ---------------------------------------------------------------------------

-- ensure_fragments: upsert per-collection fragment payloads and return, for each input position, the
-- item_fragments id the Rust loader stamps into items.fragment_id.
--
-- The caller (the Rust loader) deduplicates fragments locally and sends only the DISTINCT set (one input
-- element per unique fragment), then maps each item -> its fragment via the returned `ord`. Sending one
-- fragment per item would ship millions of duplicates when a collection has only a handful of distinct
-- fragments. The function is nonetheless dup-safe (a DISTINCT ON guards the insert), so a caller that
-- passes duplicates still gets the correct id for every position.
--
-- Each input element is {"content": <overlay or null>, "links_template": <array or null>}; the canonical
-- hash matches pgstac_hash_fragment (so it dedups identically to the SQL ingest path). ON CONFLICT keeps
-- existing rows; pre-existing ids come from item_fragments (snapshot), new ids from the INSERT's RETURNING.
CREATE OR REPLACE FUNCTION ensure_fragments(
    _collection text,
    _fragments jsonb[]
) RETURNS TABLE (ord int, frag_id bigint) AS $$
    WITH input AS (
        SELECT
            o::int AS ord,
            pgstac_hash_fragment(
                jsonb_strip_nulls(jsonb_build_object(
                    'content', NULLIF(f->'content', '{}'::jsonb),
                    'links_template', f->'links_template'
                ))
            ) AS hash,
            COALESCE(f->'content', '{}'::jsonb) AS content,
            f->'links_template' AS links_template
        FROM unnest(_fragments) WITH ORDINALITY AS u(f, o)
    ),
    distinct_hashes AS (
        SELECT DISTINCT ON (hash) hash, content, links_template
        FROM input
        ORDER BY hash
    ),
    upserted AS (
        INSERT INTO item_fragments (collection, hash, content, links_template)
        SELECT _collection, hash, content, links_template FROM distinct_hashes
        -- DO UPDATE (a no-op write) rather than DO NOTHING: it locks + RETURNS the conflicting row even when
        -- a CONCURRENT transaction committed the same (collection, hash) mid-statement. DO NOTHING returns
        -- nothing on conflict, and the old "UNION the existing rows via a separate SELECT" ran on the
        -- statement-start snapshot, so it could MISS such a concurrent insert -> that hash dropped out of the
        -- final join and the item was stamped with NO fragment_id. DO UPDATE returns every distinct hash
        -- exactly once (newly inserted or pre-existing), making the stamp concurrency-safe.
        ON CONFLICT (collection, hash) DO UPDATE SET content = item_fragments.content
        RETURNING id, hash
    )
    SELECT input.ord, upserted.id
    FROM input JOIN upserted ON input.hash = upserted.hash
    ORDER BY input.ord;
$$ LANGUAGE SQL SECURITY DEFINER;


-- ensure_partitions: create + widen every partition a batch will land in, BEFORE the load (widen-now).
-- The Rust loader passes parallel arrays of (collection, datetime, end_datetime) — one element per item.
-- Grouping happens HERE, server-side, so the month/year truncation uses the server's date_trunc (correct
-- timezone) rather than re-deriving partition boundaries in the client. One call per batch replaces the
-- loader's per-item check_partition round trips: it groups by (collection, partition window) and calls
-- check_partition once per distinct partition with that group's datetime range. Runs as its own committed
-- statement before the load transaction, so partitions exist + their stats cover the batch by the time
-- the binary COPY + flush run.
CREATE OR REPLACE FUNCTION ensure_partitions(
    _collections text[],
    _datetimes timestamptz[],
    _end_datetimes timestamptz[]
) RETURNS void AS $$
DECLARE
    r RECORD;
BEGIN
    -- Call check_partition per distinct (collection, partition window) in a DETERMINISTIC order: each
    -- check_partition takes that partition's advisory lock, so locking in a consistent order prevents two
    -- concurrent multi-partition batches from advisory-deadlocking on the locks. (flush locks in the same
    -- sorted order.) A PLPGSQL FOR loop guarantees the order; a set-returning SELECT would not.
    FOR r IN
        WITH t AS (
            SELECT
                unnest(_collections) AS collection,
                unnest(_datetimes) AS dt,
                unnest(_end_datetimes) AS edt
        ),
        j AS (
            SELECT t.collection, t.dt, t.edt, c.partition_trunc
            FROM t JOIN pgstac.collections c ON t.collection = c.id
        )
        SELECT
            collection,
            tstzrange(min(dt), max(dt), '[]') AS dtrange,
            tstzrange(min(edt), max(edt), '[]') AS edtrange
        FROM j
        GROUP BY collection, COALESCE(date_trunc(partition_trunc::text, dt), '-infinity'::timestamptz)
        ORDER BY collection, COALESCE(date_trunc(partition_trunc::text, dt), '-infinity'::timestamptz)
    LOOP
        PERFORM pgstac.check_partition(r.collection, r.dtrange, r.edtrange);
    END LOOP;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;


-- prepare_partition_for_load: per-partition metadata for the Rust direct / precheck load paths. ONE small
-- self-contained txn per partition, run BEFORE any COPY: create + widen the partition to cover this batch
-- (dt + edt + the real SPATIAL envelope, unlike ensure_partitions which passes NULL) and bump n, so
-- partition_stats is at least as wide as the data (golden rule) and search treats the partition as non-empty
-- before the data lands. Returns the partition name + the pre-load row count (n BEFORE the bump) so the
-- loader can choose its adaptive precheck path: empty -> skip the precheck; batch > n -> pull the partition's
-- (id,item_hash) to the client; n >= batch -> COPY the batch (id,hash) to a temp table + JOIN this partition.
CREATE OR REPLACE FUNCTION prepare_partition_for_load(
    _collection text,
    _dt_lo timestamptz, _dt_hi timestamptz,
    _edt_lo timestamptz, _edt_hi timestamptz,
    _xmin float8, _ymin float8, _xmax float8, _ymax float8,
    _n_add bigint,
    OUT partition_name text,
    OUT pre_load_n bigint
) AS $$
BEGIN
    partition_name := pgstac.check_partition(
        _collection,
        tstzrange(_dt_lo, _dt_hi, '[]'),
        tstzrange(_edt_lo, _edt_hi, '[]'),
        st_setsrid(st_makeenvelope(_xmin, _ymin, _xmax, _ymax), 4326)
    );
    SELECT COALESCE(n, 0) INTO pre_load_n
        FROM pgstac.partition_stats WHERE partition = partition_name;
    -- Over-estimating n is the safe direction; the async tightener computes the exact count + extent off the
    -- hot path. Single-row atomic UPDATE, so concurrent loads into the same partition serialize on the row.
    UPDATE pgstac.partition_stats
        SET n = COALESCE(n, 0) + _n_add, dirty = true, last_updated = now()
        WHERE partition = partition_name;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;


-- make_binary_staging: create a session-local TEMP staging table shaped exactly like `items`
-- (ON COMMIT DROP) and grant INSERT to pgstac_ingest so the connecting role can binary-COPY into it.
-- Created inside this SECURITY DEFINER function, so the temp table is owned by pgstac_admin (which also
-- owns `items`), letting flush_items_staging_binary read it. Returns the generated table name.
CREATE OR REPLACE FUNCTION make_binary_staging() RETURNS text AS $$
DECLARE
    _name text := format('_staging_%s', replace(gen_random_uuid()::text, '-', ''));
BEGIN
    EXECUTE format('CREATE TEMP TABLE %I (LIKE items) ON COMMIT DROP', _name);
    EXECUTE format('GRANT INSERT ON pg_temp.%I TO pgstac_ingest', _name);
    RETURN _name;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;


-- flush_items_staging_binary: move fully-dehydrated rows from a TEMP staging table into `items` with the
-- conflict policy. partition_stats (extent + n + dirty) is set entirely by prepare_partition_for_load in
-- the preflight, so this writes only `items`:
--        ignore  -> ON CONFLICT DO NOTHING (idempotent; orphans the old row on a cross-partition move)
--        upsert  -> delete a changed row IN THE PARTITION IT ROUTES TO (window-pruned), then insert. A
--                   datetime change that stays in the partition is applied; one that moves the item to a
--                   different partition orphans the old row (use 'delsert').
--        delsert -> delete a changed row CROSS-partition (by collection+id, move-safe), then insert
--        error   -> plain INSERT (raises on any duplicate)
-- Returns the number of rows inserted.
CREATE OR REPLACE FUNCTION flush_items_staging_binary(
    _staging text,
    _policy text DEFAULT 'ignore'
) RETURNS bigint AS $$
DECLARE
    nrows bigint;
BEGIN
    IF _policy = 'ignore' THEN
        EXECUTE format('INSERT INTO items SELECT * FROM %1$I ON CONFLICT DO NOTHING', _staging);
    ELSIF _policy = 'error' THEN
        EXECUTE format('INSERT INTO items SELECT * FROM %1$I', _staging);
    ELSIF _policy = 'upsert' THEN
        -- Fast SAME-partition upsert: delete a changed row only in the partition the incoming row routes to.
        -- The window range [date_trunc(trunc, s.datetime), + 1 trunc) is derived per staged row, so the
        -- planner runtime-prunes `items` to that one partition (no cross-partition scan). A datetime change
        -- within the partition is applied; one that MOVES the item to another partition isn't seen here, so
        -- the old row orphans (use 'delsert'). NULL partition_trunc => the collection's single partition.
        EXECUTE format($q$
            DELETE FROM items i USING %1$I s JOIN collections c ON c.id = s.collection
            WHERE i.collection = s.collection AND i.id = s.id
              AND i.datetime >= (CASE WHEN c.partition_trunc IS NULL THEN '-infinity'::timestamptz
                                      ELSE date_trunc(c.partition_trunc::text, s.datetime) END)
              AND i.datetime <  (CASE WHEN c.partition_trunc IS NULL THEN 'infinity'::timestamptz
                                      ELSE date_trunc(c.partition_trunc::text, s.datetime)
                                           + ('1 ' || c.partition_trunc::text)::interval END)
              AND ( %2$s )
        $q$, _staging, items_content_distinct_sql('i', 's'));
        EXECUTE format('INSERT INTO items SELECT * FROM %1$I ON CONFLICT DO NOTHING', _staging);
    ELSIF _policy = 'delsert' THEN
        -- Move-safe CROSS-partition upsert: delete the old row wherever it lives (by collection+id, no
        -- datetime bound, so it probes every partition), then insert.
        EXECUTE format($q$
            DELETE FROM items i USING %1$I s
            WHERE i.id = s.id AND i.collection = s.collection AND ( %2$s )
        $q$, _staging, items_content_distinct_sql('i', 's'));
        EXECUTE format('INSERT INTO items SELECT * FROM %1$I ON CONFLICT DO NOTHING', _staging);
    ELSE
        RAISE EXCEPTION 'unknown conflict policy % (expected ignore | upsert | delsert | error)', _policy;
    END IF;
    GET DIAGNOSTICS nrows = ROW_COUNT;
    RETURN nrows;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;
-- END FRAGMENT: 003c_ingest.sql

-- BEGIN FRAGMENT: 004_search.sql
-- Search hashing

-- pgstac_hash: sha256 of a UTF8-encoded text, returned as hex.
CREATE OR REPLACE FUNCTION pgstac_hash(data text) RETURNS text AS $$
    SELECT encode(sha256(convert_to(data, 'UTF8')), 'hex');
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE STRICT;

-- search_hash_from_where: produce a deterministic hash from a WHERE clause and optional metadata.
CREATE OR REPLACE FUNCTION search_hash_from_where(_where text, _metadata jsonb DEFAULT '{}'::jsonb) RETURNS text AS $$
    SELECT pgstac_hash(format('%s|%s', _where, coalesce(_metadata, '{}'::jsonb)::text));
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;

-- search_hash: produce a deterministic hash from a STAC search JSON.
CREATE OR REPLACE FUNCTION search_hash(_search jsonb, _metadata jsonb DEFAULT '{}'::jsonb) RETURNS text AS $$
    SELECT search_hash_from_where(stac_search_to_where(_search), _metadata);
$$ LANGUAGE SQL STABLE PARALLEL SAFE;

-- Searches cache table stores derived search metadata (WHERE clause, ORDER BY,
-- hash) so that repeated equivalent queries re-use the cached context count.
-- metadata IS NULL = anonymous search (short-lived GC).
CREATE TABLE IF NOT EXISTS searches(
    hash text PRIMARY KEY,
    search jsonb NOT NULL,
    _where text,
    orderby text,
    lastused timestamptz DEFAULT now(),
    usecount bigint DEFAULT 0,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamptz DEFAULT now(),
    statslastupdated timestamptz,
    context_count bigint
);
CREATE INDEX IF NOT EXISTS searches_lastused_anon_idx
    ON searches (lastused) WHERE metadata IS NOT NULL;

-- stac_search_to_where: convert a STAC search JSON to a SQL WHERE clause
-- via the unified CQL2 representation (search_to_cql2 -> cql2_query).
-- Returns ' TRUE ' for an empty/unconstrained search.
CREATE OR REPLACE FUNCTION stac_search_to_where(j jsonb) RETURNS text AS $$
DECLARE _where text := cql2_query(search_to_cql2(j));
BEGIN
    IF _where IS NULL OR btrim(_where) = '' THEN RETURN ' TRUE '; END IF;
    RETURN _where;
END;
$$ LANGUAGE PLPGSQL STABLE;

-- where_stats: estimate or count matching rows for a search, cached in the searches
-- table. The inclamp parameter is a sound partition clamp (collection + datetime range)
-- that lets the planner prune partitions for the count query.
CREATE OR REPLACE FUNCTION where_stats(
    inhash text, inwhere text, updatestats boolean default false,
    conf jsonb default null, inclamp text default null
) RETURNS searches AS $$
DECLARE
    t timestamptz; i interval; explain_json jsonb;
    sw searches%ROWTYPE; sw_statslastupdated timestamptz;
    sw_estimated_count bigint; sw_estimated_cost float;
    _context text := lower(context(conf));
    _stats_ttl interval := context_stats_ttl(conf);
    _estimated_cost_threshold float := context_estimated_cost(conf);
    _estimated_count_threshold int := context_estimated_count(conf);
    ro bool := pgstac.readonly(conf);
BEGIN
    IF updatestats THEN _stats_ttl := '0'::interval; END IF;
    IF _context = 'off' THEN RETURN sw; END IF;
    SELECT * INTO sw FROM searches WHERE hash = inhash;
    IF sw IS NULL THEN sw.hash := inhash; sw._where := inwhere; sw_statslastupdated := NULL;
    ELSE sw_statslastupdated := sw.statslastupdated; END IF;
    IF sw IS NOT NULL AND sw.statslastupdated IS NOT NULL AND sw.context_count IS NOT NULL
       AND now() - sw_statslastupdated <= _stats_ttl THEN RETURN sw; END IF;
    t := clock_timestamp();
    EXECUTE format('EXPLAIN (format json) SELECT 1 FROM items i WHERE %s',
                   concat_ws(' AND ', inclamp, inwhere)) INTO explain_json;
    i := clock_timestamp() - t;
    sw_estimated_count := (explain_json->0->'Plan'->>'Plan Rows')::bigint;
    sw_estimated_cost := (explain_json->0->'Plan'->>'Total Cost')::float;
    IF _context = 'auto' AND sw_estimated_count >= _estimated_count_threshold
       AND sw_estimated_cost >= _estimated_cost_threshold THEN
        sw.context_count := sw_estimated_count;
        IF NOT ro THEN
            UPDATE searches SET statslastupdated = now(), context_count = sw.context_count
            WHERE hash = inhash AND statslastupdated IS NOT DISTINCT FROM sw_statslastupdated
            RETURNING * INTO sw;
            IF sw IS NULL THEN SELECT * INTO sw FROM searches WHERE hash = inhash; END IF;
        END IF;
        RETURN sw;
    END IF;
    t := clock_timestamp();
    EXECUTE format('SELECT count(*) FROM items i WHERE %s', concat_ws(' AND ', inclamp, inwhere))
        INTO sw.context_count;
    i := clock_timestamp() - t;
    IF NOT ro THEN
        UPDATE searches SET statslastupdated = now(), context_count = sw.context_count
        WHERE hash = inhash AND statslastupdated IS NOT DISTINCT FROM sw_statslastupdated
        RETURNING * INTO sw;
        IF sw IS NULL THEN SELECT * INTO sw FROM searches WHERE hash = inhash; END IF;
    END IF;
    RETURN sw;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

-- register_search: persist a pre-derived search row in the searches cache table
-- (hash, _where, orderby, search, metadata already populated). Best-effort and
-- non-blocking: returns the canonical cached row.
CREATE OR REPLACE FUNCTION register_search(search searches) RETURNS searches AS $$
DECLARE cached_search searches%ROWTYPE;
BEGIN
    IF pgstac.readonly() THEN RETURN search; END IF;
    UPDATE searches SET lastused = now(), usecount = searches.usecount + 1
    WHERE ctid = (SELECT ctid FROM searches WHERE hash = search.hash FOR UPDATE SKIP LOCKED LIMIT 1)
    RETURNING * INTO cached_search;
    IF cached_search IS NULL THEN
        IF pg_try_advisory_xact_lock(hashtext(search.hash)) THEN
            INSERT INTO searches (hash, search, _where, orderby, lastused, usecount, metadata)
                VALUES (search.hash, search.search, search._where, search.orderby, now(), 1, search.metadata)
                ON CONFLICT (hash) DO UPDATE SET lastused = EXCLUDED.lastused, usecount = searches.usecount + 1
                RETURNING * INTO cached_search;
        END IF;
        IF cached_search IS NULL THEN
            SELECT * INTO cached_search FROM searches WHERE hash = search.hash;
        END IF;
    END IF;
    IF cached_search IS NOT NULL THEN
        cached_search._where := search._where;
        cached_search.orderby := search.orderby;
        RETURN cached_search;
    END IF;
    RETURN search;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER SET search_path TO pgstac, public;

-- search_query: derive hash/where/orderby from a STAC search JSON, register
-- it, and return only the hash and metadata. Used by external callers.
CREATE OR REPLACE FUNCTION search_query(
    _search jsonb = '{}'::jsonb,
    _metadata jsonb = '{}'::jsonb
) RETURNS TABLE(hash text, metadata jsonb) AS $$
DECLARE search searches%ROWTYPE;
BEGIN
    search.search := _search;
    search.metadata := _metadata;
    search._where := stac_search_to_where(_search);
    search.hash := search_hash_from_where(search._where, search.metadata);
    search.orderby := keyset_orderby(_search);
    search.lastused := now();
    search.usecount := 1;
    search := register_search(search);
    RETURN QUERY SELECT search.hash, search.metadata;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER SET search_path TO pgstac, public;

-- search_fromhash: lookup a cached search by its hash.
CREATE OR REPLACE FUNCTION search_fromhash(_hash text) RETURNS searches AS $$
    SELECT * FROM searches WHERE hash = _hash LIMIT 1;
$$ LANGUAGE SQL STRICT;

-- search_from_json: same as search_query — derive hash/where/orderby, register,
-- and return hash + metadata. Used internally by search_page and search_plan.
CREATE OR REPLACE FUNCTION search_from_json(
    _search jsonb DEFAULT '{}'::jsonb,
    _metadata jsonb DEFAULT '{}'::jsonb
) RETURNS TABLE(hash text, metadata jsonb) AS $$
DECLARE search searches%ROWTYPE;
BEGIN
    search.search := _search;
    search.metadata := _metadata;
    search._where := stac_search_to_where(_search);
    search.hash := search_hash_from_where(search._where, search.metadata);
    search.orderby := keyset_orderby(_search);
    search.lastused := now();
    search.usecount := 1;
    search := register_search(search);
    RETURN QUERY SELECT search.hash, search.metadata;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER SET search_path TO pgstac, public;

-- field_included: STAC fields include/exclude decision over text[] arrays (the array-form used by
-- the column projector fields_to_itemcols). include_field() is the equivalent over a fields jsonb
-- (used by content_hydrate); both apply the same rule: exclude wins, then an explicit include list
-- restricts to its members, otherwise everything is included.
CREATE OR REPLACE FUNCTION field_included(_field text, _includes text[], _excludes text[])
RETURNS boolean LANGUAGE sql IMMUTABLE AS $$
    SELECT CASE
        WHEN _field = ANY(_excludes) THEN false
        WHEN array_length(_includes, 1) IS NOT NULL THEN _field = ANY(_includes)
        ELSE true END;
$$;

-- needs_fragment: determine whether satisfying the requested fields for the
-- query's collections requires the item_fragments row (shared asset/property/link values).
-- Returns false (fragment not needed) only when an explicit include list can be
-- satisfied from item columns alone.
CREATE OR REPLACE FUNCTION needs_fragment(fields jsonb, _colls text[]) RETURNS boolean AS $$
DECLARE
    includes text[] := ARRAY(SELECT jsonb_array_elements_text(fields->'include'));
    promoted text[] := ARRAY['datetime','start_datetime','end_datetime']
                       || ARRAY(SELECT name FROM promoted_item_property_defs());
    inc text; propkey text; prop_paths text[] := ARRAY[]::text[];
BEGIN
    IF array_length(includes, 1) IS NULL THEN RETURN true; END IF;
    IF _colls IS NULL THEN RETURN true; END IF;
    FOREACH inc IN ARRAY includes LOOP
        IF inc IN ('assets','links','stac_version','stac_extensions','properties')
           OR inc LIKE 'assets.%' OR inc LIKE 'links.%' THEN
            RETURN true;
        ELSIF inc LIKE 'properties.%' THEN
            propkey := substring(inc FROM 'properties\\.(.*)');
            IF NOT (propkey = ANY (promoted)) THEN RETURN true; END IF;
            prop_paths := prop_paths || propkey;
        END IF;
    END LOOP;
    IF array_length(prop_paths, 1) IS NOT NULL AND EXISTS (
        SELECT 1 FROM collections c, unnest(c.fragment_config) cfg(p),
             LATERAL (SELECT fragment_path_array(cfg.p) AS parr) z
        WHERE c.id = ANY (_colls)
          AND z.parr[1] = 'properties'
          AND (array_length(z.parr, 1) = 1 OR z.parr[2] = ANY (prop_paths))
    ) THEN RETURN true; END IF;
    RETURN false;
END;
$$ LANGUAGE PLPGSQL STABLE PARALLEL SAFE;

-- fields_to_itemcols: produce a SELECT list of item columns in attnum order.
-- Heavy columns (geometry, bbox, assets, links, properties, extra) are emitted as
-- NULL::type AS <col> when their controlling field is excluded/not-included: the
-- column is kept (named) so the result schema is stable across any `fields` value
-- -- a client preparing this query once can step bands without re-binding columns --
-- while the heavy value itself is never transferred.
-- When _skip_fragment is true (the caller determined the requested fields are
-- satisfiable from item columns alone, via needs_fragment), fragment_id is emitted
-- as NULL too: a client driving this query then sees no fragment_id and skips the
-- per-row item_fragments lookup entirely -- the fragment-skip is carried in the
-- projection itself, not a separate flag.
CREATE OR REPLACE FUNCTION fields_to_itemcols(fields jsonb DEFAULT '{}'::jsonb, _skip_fragment boolean DEFAULT false) RETURNS text AS $$
DECLARE
    includes text[] := ARRAY(SELECT jsonb_array_elements_text(fields->'include'));
    excludes text[] := ARRAY(SELECT jsonb_array_elements_text(fields->'exclude'));
    cols text;
BEGIN
    SELECT string_agg(
        CASE
          WHEN a.attname = 'fragment_id' AND _skip_fragment
          THEN format('NULL::%s AS %I', format_type(a.atttypid, a.atttypmod), a.attname)
          WHEN a.attname = ANY (ARRAY['geometry','bbox','assets','links','link_hrefs',
                                      'extra','properties','stac_version','stac_extensions'])
               AND NOT field_included(CASE WHEN a.attname = 'link_hrefs' THEN 'links' ELSE a.attname END,
                                      includes, excludes)
          THEN format('NULL::%s AS %I', format_type(a.atttypid, a.atttypmod), a.attname)
          ELSE format('i.%I', a.attname)
        END, ', ' ORDER BY a.attnum)
    INTO cols
    FROM pg_attribute a
    WHERE a.attrelid = 'items'::regclass AND a.attnum > 0 AND NOT a.attisdropped;
    RETURN cols;
END;
$$ LANGUAGE PLPGSQL STABLE;

-- search_page: server-hydrate page primitive with keyset pagination and
-- adaptive cumulative-count bands over partition_bounds' per-month histogram.
-- Returns typed page components (features json, count, next/prev tokens) so
-- search() can compose the FeatureCollection envelope without re-parsing json.
CREATE OR REPLACE FUNCTION search_page(
    _search jsonb DEFAULT '{}'::jsonb,
    _limit  int   DEFAULT 100,
    _token  text  DEFAULT NULL,
    _prev   boolean DEFAULT false,
    _fields jsonb DEFAULT '{}'::jsonb,
    OUT features        json,
    OUT number_returned integer,
    OUT next_token      text,
    OUT prev_token      text,
    OUT number_matched  bigint
) RETURNS record LANGUAGE plpgsql SECURITY DEFINER SET search_path TO pgstac, public AS $$
DECLARE
    band_margin CONSTANT numeric := 3.0;
    band_safety CONSTANT numeric := 1.5;
    _where text; _hash text; total_count bigint;
    keyset_w text; full_where text; orderby_str text; keys_proj text;
    lead_field text; eff_lead_dir text; datetime_leading boolean;
    acc json := '[]'::json; cnt bigint := 0; has_more boolean := false;
    first_k text[]; last_k text[]; fwd_first_k text[]; fwd_last_k text[];
    have_row boolean := false; next_tok text; prev_tok text;
    next_present boolean; prev_present boolean;
    _env pred_envelope; _cql2 jsonb;
    bnds record; clamp text; clamped_where text;
    band_cap_months CONSTANT int := 18;
    page_rows items[] := '{}'::items[]; chunk_rows items[];
    target int := _limit + 1; got int := 0; got_band int;
    is_asc boolean; band record;
    band_target numeric; obs_sel numeric; band_where text;
    guard int := 0; cum_scanned bigint := 0;
    proj_expr text; mo interval := interval '1 month';
    cursor_idx int;
BEGIN
    -- The requested STAC `fields` live in the search request; honor them over the (defaulted)
    -- parameter so include/exclude projection is actually applied for search().
    _fields := coalesce(_search->'fields', _fields, '{}'::jsonb);
    _cql2 := search_to_cql2(_search);
    _where := cql2_query(_cql2);
    IF _where IS NULL OR btrim(_where) = '' THEN _where := ' TRUE '; END IF;
    _hash := search_hash_from_where(_where, '{}'::jsonb);
    _env := cql2_envelope(_cql2);

    SELECT * INTO bnds FROM partition_bounds(_env);
    IF bnds.collections IS NOT NULL THEN
        clamp := format('i.collection = ANY (%L::text[])', bnds.collections);
    END IF;

    SELECT string_agg(expr||' '||CASE WHEN _prev THEN (CASE dir WHEN 'ASC' THEN 'DESC' ELSE 'ASC' END) ELSE dir END, ', ' ORDER BY ord),
           'ARRAY['||string_agg(format('(%s)::text', expr), ',' ORDER BY ord)||']::text[]',
           (array_agg(field ORDER BY ord))[1],
           (array_agg(CASE WHEN _prev THEN (CASE dir WHEN 'ASC' THEN 'DESC' ELSE 'ASC' END) ELSE dir END ORDER BY ord))[1]
    INTO orderby_str, keys_proj, lead_field, eff_lead_dir
    FROM keyset_sortkeys(_search);
    datetime_leading := (lead_field = 'datetime');
    is_asc := (eff_lead_dir = 'ASC');

    IF context(_search->'conf') <> 'off' THEN
        DECLARE s searches%ROWTYPE; BEGIN
            s.search := _search; s.metadata := '{}'::jsonb; s._where := _where; s.hash := _hash;
            s.orderby := keyset_orderby(_search); s.lastused := now(); s.usecount := 1;
            PERFORM register_search(s);
        END;
        total_count := (where_stats(_hash, _where, false, _search->'conf', clamp)).context_count;
    END IF;

    IF _token IS NOT NULL THEN
        keyset_w := keyset_where(_search, keyset_decode(_token), _prev);
    END IF;
    full_where := concat_ws(' AND ', _where, keyset_w);
    IF full_where IS NULL OR btrim(full_where) = '' THEN full_where := 'TRUE'; END IF;
    clamped_where := concat_ws(' AND ', clamp, full_where);
    IF clamped_where IS NULL OR btrim(clamped_where) = '' THEN clamped_where := 'TRUE'; END IF;

    -- Per-row projection. When the requested fields can be satisfied from item columns alone
    -- (needs_fragment, evaluated once for the whole query), tell content_hydrate to skip the shared
    -- item_fragments lookup entirely; otherwise it fetches and merges the fragment per row.
    IF needs_fragment(_fields, bnds.collections) THEN
        proj_expr := format('content_hydrate(i, %L::jsonb)', _fields);
    ELSE
        proj_expr := format('content_hydrate(i, %L::jsonb, true)', _fields);
    END IF;

    IF datetime_leading AND array_length(bnds.months, 1) IS NOT NULL THEN
        -- Start the band walk at the leading edge for the sort direction: oldest month for ascending,
        -- most recent month for descending. (A descending walk that started at the oldest band would
        -- collect the oldest items and never reach the recent months.)
        cursor_idx := CASE WHEN is_asc THEN 1 ELSE array_length(bnds.months, 1) END;
        band_target := target * band_margin;
        WHILE got < target AND guard < 80 LOOP
            guard := guard + 1;
            SELECT * INTO band FROM next_band(bnds.counts, cursor_idx, band_target, band_cap_months, NOT is_asc);
            -- a valid band must be processed even when next_band also flags done (it consumed the
            -- last bucket); only stop when there is no band at all.
            EXIT WHEN band.band_start_idx IS NULL;
            band_where := format('i.datetime >= %L AND i.datetime < %L AND (%s)',
                bnds.months[band.band_start_idx], bnds.months[band.band_end_idx] + mo, full_where);
            EXECUTE format('SELECT array_agg(i ORDER BY %s) FROM (SELECT * FROM items i WHERE %s ORDER BY %s LIMIT %s) i',
                orderby_str, band_where, orderby_str, target - got) INTO chunk_rows;
            got_band := coalesce(array_length(chunk_rows, 1), 0);
            IF chunk_rows IS NOT NULL THEN page_rows := page_rows || chunk_rows; got := got + got_band; END IF;
            cum_scanned := cum_scanned + band.scanned;
            cursor_idx := band.next_cursor_idx;
            EXIT WHEN got >= target;
            obs_sel := GREATEST(got::numeric, 0.5) / GREATEST(cum_scanned, 1);
            band_target := ((target - got) / obs_sel) * band_safety;
        END LOOP;
    ELSE
        EXECUTE format('SELECT array_agg(i ORDER BY %s) FROM (SELECT * FROM items i WHERE %s ORDER BY %s LIMIT %s) i',
            orderby_str, clamped_where, orderby_str, target) INTO page_rows;
    END IF;

    EXECUTE format($q$
        WITH page AS (
            SELECT %1$s AS content,
                   CASE WHEN row_number() OVER (ORDER BY %2$s) IN (1, %3$s) THEN %4$s END AS keys,
                   row_number() OVER (ORDER BY %2$s) AS rn
            FROM unnest($1::items[]) i
        ),
        counts AS (SELECT count(*) AS n FROM page)
        SELECT
            coalesce(json_agg(content ORDER BY rn) FILTER (WHERE rn <= %3$s), '[]'::json),
            (SELECT n FROM counts),
            (SELECT keys FROM page WHERE rn = 1),
            (SELECT keys FROM page WHERE rn = LEAST(%3$s, (SELECT n FROM counts)::int))
        FROM page
    $q$, proj_expr, orderby_str, _limit, keys_proj)
    USING page_rows INTO acc, cnt, first_k, last_k;

    IF acc IS NULL THEN acc := '[]'::json; END IF;
    has_more := cnt > _limit;
    have_row := cnt > 0;

    IF _prev THEN
        acc := (SELECT coalesce(json_agg(e ORDER BY ord DESC), '[]'::json) FROM json_array_elements(acc) WITH ORDINALITY t(e, ord));
        fwd_first_k := last_k; fwd_last_k := first_k;
        next_present := (_token IS NOT NULL);
        prev_present := has_more;
    ELSE
        fwd_first_k := first_k; fwd_last_k := last_k;
        next_present := has_more;
        prev_present := (_token IS NOT NULL);
    END IF;
    IF have_row AND next_present THEN next_tok := keyset_encode(fwd_last_k); END IF;
    IF have_row AND prev_present THEN prev_tok := keyset_encode(fwd_first_k); END IF;

    features := acc;
    number_returned := json_array_length(acc);
    next_token := next_tok;
    prev_token := prev_tok;
    number_matched := total_count;
END;
$$;

-- search: FeatureCollection API wrapper
CREATE OR REPLACE FUNCTION search(_search jsonb DEFAULT '{}'::jsonb) RETURNS json AS $$
DECLARE
    -- caller-provided limit/token come from the search body; default to the configured page size.
    _limit  int := coalesce((_search->>'limit')::int,
                            nullif(get_setting('default_page_size', _search->'conf'), '')::int, 10);
    _token  text := _search->>'token';
    -- The keyset is the token minus its next/prev prefix; an empty token means no keyset (first
    -- page). A non-empty keyset that does not decode raises in keyset_decode downstream.
    keyset  text := nullif(regexp_replace(coalesce(_token,''), '^(next|prev):', ''), '');
    is_prev boolean := (_token LIKE 'prev:%') AND keyset IS NOT NULL;
    pg record;
    burl text := rtrim(coalesce(base_url(_search->'conf'), ''), '/');
    links jsonb := '[]'::jsonb;
    out json;
BEGIN
    SELECT * INTO pg FROM search_page(_search, _limit, keyset, is_prev);
    links := links
      || jsonb_build_object('rel','root','type','application/json','href', burl)
      || jsonb_build_object('rel','self','type','application/json','href',burl||'/search');
    IF pg.next_token IS NOT NULL THEN
        links := links || jsonb_build_object('rel','next','type','application/geo+json','method','GET',
            'href', burl||'/search?token=next:'||pg.next_token);
    END IF;
    IF pg.prev_token IS NOT NULL THEN
        links := links || jsonb_build_object('rel','prev','type','application/geo+json','method','GET',
            'href', burl||'/search?token=prev:'||pg.prev_token);
    END IF;
    IF pg.number_matched IS NOT NULL THEN
        out := json_build_object(
            'type','FeatureCollection',
            'features', coalesce(pg.features,'[]'::json),
            'links', links,
            'numberReturned', pg.number_returned,
            'numberMatched', pg.number_matched);
    ELSE
        out := json_build_object(
            'type','FeatureCollection',
            'features', coalesce(pg.features,'[]'::json),
            'links', links,
            'numberReturned', pg.number_returned);
    END IF;
    RETURN out;
END;
$$ LANGUAGE PLPGSQL;

-- search_plan: client-streaming entry point
CREATE OR REPLACE FUNCTION search_plan(
    _search jsonb DEFAULT '{}'::jsonb,
    _token  text  DEFAULT NULL,
    _limit  int   DEFAULT NULL,
    OUT query        text,
    OUT histogram    jsonb,
    OUT min_datetime timestamptz,
    OUT max_datetime timestamptz,
    OUT max_count    bigint,
    OUT lead_desc    boolean,
    OUT ctx_query    text,
    OUT datetime_leading boolean,
    OUT context_count    bigint
) RETURNS record LANGUAGE plpgsql VOLATILE SECURITY DEFINER SET search_path TO pgstac, public AS $$
DECLARE
    _cql2   jsonb := search_to_cql2(_search);
    _where  text  := cql2_query(_cql2);
    is_prev boolean := _token LIKE 'prev:%';
    keyset  text  := nullif(regexp_replace(coalesce(_token, ''), '^(next|prev):', ''), '');
    keyset_w text; full_where text; orderby_str text; collist text;
    lead_field text; eff_dir text; _env pred_envelope; _hash text;
    bnds record; coll_clamp text := ''; clamp text;
BEGIN
    IF _where IS NULL OR btrim(_where) = '' THEN _where := ' TRUE '; END IF;
    orderby_str := keyset_orderby(_search, is_prev);
    SELECT (array_agg(field ORDER BY ord))[1],
           (array_agg(CASE WHEN is_prev THEN (CASE dir WHEN 'ASC' THEN 'DESC' ELSE 'ASC' END) ELSE dir END ORDER BY ord))[1]
    INTO lead_field, eff_dir FROM keyset_sortkeys(_search);
    datetime_leading := (lead_field = 'datetime');
    lead_desc := (eff_dir = 'DESC');

    IF keyset IS NOT NULL THEN
        keyset_w := keyset_where(_search, keyset_decode(keyset), is_prev);
    END IF;
    full_where := concat_ws(' AND ', _where, keyset_w);
    IF full_where IS NULL OR btrim(full_where) = '' THEN full_where := 'TRUE'; END IF;

    _env := cql2_envelope(_cql2);
    SELECT * INTO bnds FROM partition_bounds(_env);
    min_datetime := bnds.months[1];
    max_datetime := bnds.months[array_length(bnds.months, 1)];
    max_count := bnds.total_count;
    IF bnds.collections IS NOT NULL THEN
        clamp := format('i.collection = ANY(%L::text[])', bnds.collections);
    END IF;
    IF bnds.collections IS NOT NULL THEN
        coll_clamp := format('i.collection = ANY(%L::text[]) AND ', bnds.collections);
    END IF;

    -- Build the projection now that the resolved collections are known: when the requested fields are
    -- satisfiable from item columns alone (needs_fragment is false), fragment_id is nulled in the
    -- projection so a client driving this query never looks up item_fragments -- the fragment-skip
    -- rides in the returned query's SELECT list, not a separate flag.
    collist := fields_to_itemcols(
        coalesce(_search->'fields', '{}'::jsonb),
        NOT needs_fragment(coalesce(_search->'fields', '{}'::jsonb), bnds.collections));

    IF datetime_leading AND array_length(bnds.months, 1) IS NOT NULL THEN
        -- collections baked in as a literal so the query is parameterized only by $1 (band low),
        -- $2 (band high), $3 (limit): the client prepares it once and binds per histogram band.
        query := format(
            'SELECT %s FROM items i WHERE %si.datetime >= $1 AND i.datetime < $2 AND (%s) ORDER BY %s LIMIT $3',
            collist, coll_clamp, full_where, orderby_str);
        -- serialize the per-month histogram (months[]/counts[]) to jsonb for the streaming client
        histogram := (
            SELECT jsonb_agg(jsonb_build_object('m', m, 'n', n) ORDER BY ord)
            FROM unnest(bnds.months, bnds.counts) WITH ORDINALITY AS h(m, n, ord)
        );
    ELSE
        DECLARE dt_clamp text := ''; BEGIN
            IF array_length(bnds.months, 1) IS NOT NULL THEN
                -- months[] holds month *starts*; the last bucket spans [start, start + 1 month), so the
                -- upper bound must be exclusive of the next month, not <= the last month's start (which
                -- would drop items dated after the start of the final month).
                dt_clamp := format('i.datetime >= %L AND i.datetime < %L AND ', bnds.months[1], bnds.months[array_length(bnds.months, 1)] + interval '1 month');
            END IF;
            query := format(
                'SELECT %s FROM items i WHERE %s%s(%s) ORDER BY %s LIMIT $1',
                collist, coll_clamp, dt_clamp, full_where, orderby_str);
            histogram := NULL;
        END;
    END IF;

    IF context(_search->'conf') <> 'off' THEN
        _hash := search_hash_from_where(_where, '{}'::jsonb);
        DECLARE s searches%ROWTYPE; BEGIN
            s.search := _search; s.metadata := '{}'::jsonb; s._where := _where; s.hash := _hash;
            s.orderby := keyset_orderby(_search); s.lastused := now(); s.usecount := 1;
            PERFORM register_search(s);
        END;
        -- Inline the cached count when stats are fresh (same rule as where_stats), so the client
        -- can skip ctx_query on a cache hit. NULL => miss/stale => client races ctx_query.
        SELECT s2.context_count INTO context_count
        FROM searches s2
        WHERE s2.hash = _hash
          AND s2.statslastupdated IS NOT NULL
          AND s2.context_count IS NOT NULL
          AND now() - s2.statslastupdated <= context_stats_ttl(_search->'conf');
        ctx_query := format('SELECT (where_stats(%L, %L, false, %L, %L)).context_count',
                            _hash, _where, _search->'conf', clamp);
    ELSE
        ctx_query := NULL;
        context_count := NULL;
    END IF;
END;
$$;
-- END FRAGMENT: 004_search.sql

-- BEGIN FRAGMENT: 004a_collectionsearch.sql
-- collections_asitems: Exposes collections as pseudo-items for CQL2 filtering.
-- The 'properties' column is the collection content with the standard top-level
-- STAC fields stripped, so CQL2 expressions like {"property":"title"} resolve
-- correctly when filtering collections via /collections?filter=... endpoints.
CREATE OR REPLACE VIEW collections_asitems AS
SELECT
    id,
    geometry,
    'collections' AS collection,
    datetime,
    end_datetime,
    -- Expose collection metadata as properties so CQL2 {"property":"title"} etc. work.
    content - '{links,assets,stac_version,stac_extensions}' AS properties,
    jsonb_build_object(
        'properties', content - '{links,assets,stac_version,stac_extensions}',
        'links', content->'links',
        'assets', content->'assets',
        'stac_version', content->'stac_version',
        'stac_extensions', content->'stac_extensions'
    ) AS content,
    content as collectionjson
FROM collections;


-- collection_search_plan: the collection counterpart of search_plan -- the CLIENT-STREAMING entry
-- for collections. Returns the data query (collection content + keyset keys) the client PREPAREs and
-- the always-on numberMatched query. Built from the SAME building blocks as search_plan/search_page
-- (search_to_cql2 -> cql2_query, keyset_*). No datetime bands: collections aren't partitioned by
-- time. Unlike items, collections aren't split-storage, so the query yields the collection content
-- jsonb directly (no client-side assembly) -- which is why collection_search() can run it as-is.
--   query     : SELECT jsonb_fields(collectionjson, <fields>) AS content, <keys> AS keys
--               FROM collections_asitems WHERE <where + keyset seek> ORDER BY <orderby> LIMIT $1
--   ctx_query : SELECT count(*) FROM collections_asitems WHERE <where>   (numberMatched, always)
CREATE OR REPLACE FUNCTION collection_search_plan(
    _search jsonb DEFAULT '{}'::jsonb,
    _token  text  DEFAULT NULL,
    OUT query     text,
    OUT ctx_query text
) RETURNS record AS $$
DECLARE
    is_prev boolean := _token LIKE 'prev:%';
    keyset text := nullif(regexp_replace(coalesce(_token, ''), '^(next|prev):', ''), '');
    _fields jsonb := coalesce(_search->'fields', '{}'::jsonb);
    -- collections default to id ASC unless the caller supplied an explicit sortby.
    _eff jsonb := CASE WHEN _search ? 'sortby' THEN _search
                       ELSE _search || '{"sortby":[{"field":"id","direction":"asc"}]}'::jsonb END;
    _cql2 jsonb := search_to_cql2(_search);
    _where text := coalesce(nullif(btrim(cql2_query(_cql2)), ''), 'TRUE');
    orderby_str text; keys_proj text; keyset_w text; full_where text;
BEGIN
    -- effective ORDER BY (reversed for prev) + the key projection, from the keyset keys.
    SELECT string_agg(expr || ' ' || CASE WHEN is_prev THEN (CASE dir WHEN 'ASC' THEN 'DESC' ELSE 'ASC' END) ELSE dir END, ', ' ORDER BY ord),
           'ARRAY[' || string_agg(format('(%s)::text', expr), ',' ORDER BY ord) || ']::text[]'
    INTO orderby_str, keys_proj
    FROM keyset_sortkeys(_eff);

    IF keyset IS NOT NULL THEN
        keyset_w := keyset_where(_eff, keyset_decode(keyset), is_prev);
    END IF;
    full_where := concat_ws(' AND ', _where, keyset_w);
    IF full_where IS NULL OR btrim(full_where) = '' THEN full_where := 'TRUE'; END IF;

    query := format(
        $q$ SELECT jsonb_fields(collectionjson, %L) AS content, %s AS keys
            FROM collections_asitems WHERE %s ORDER BY %s LIMIT $1 $q$,
        _fields, keys_proj, full_where, orderby_str);
    ctx_query := format('SELECT count(*) FROM collections_asitems WHERE %s', _where);
END;
$$ LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path TO pgstac, public;


-- collection_search: keyset-paginated collection listing.
-- Builds its data + numberMatched queries via collection_search_plan (one source of truth, shared
-- with the client-streaming path), fetches _limit+1 to detect a further page, and links next/prev as
-- opaque keyset tokens. Collections default to id ASC. numberMatched is ALWAYS returned (small table).
CREATE OR REPLACE FUNCTION collection_search(
    _search jsonb DEFAULT '{}'::jsonb
) RETURNS jsonb AS $$
DECLARE
    _limit int := coalesce((_search->>'limit')::float::int, 10);
    _token text := _search->>'token';
    is_prev boolean := _token LIKE 'prev:%';
    keyset text := nullif(regexp_replace(coalesce(_token, ''), '^(next|prev):', ''), '');
    _q text; _ctx text;
    number_matched bigint;
    number_returned bigint;
    acc jsonb := '[]'::jsonb; cnt int := 0;
    first_k text[]; last_k text[]; fwd_first_k text[]; fwd_last_k text[];
    has_more boolean; next_present boolean; prev_present boolean;
    next_tok text; prev_tok text;
    links jsonb := '[]'::jsonb;
    burl text := concat(rtrim(base_url(_search->'conf'), '/'), '/collections');
    -- typed loop targets (not a `record`) so plpgsql_check can analyze the dynamic EXECUTE.
    _content jsonb; _keys text[];
BEGIN
    SELECT query, ctx_query INTO _q, _ctx FROM collection_search_plan(_search, _token);
    EXECUTE _ctx INTO number_matched;   -- numberMatched, always

    -- the plan query returns (content, keys); +1 over _limit detects a further page.
    FOR _content, _keys IN EXECUTE _q USING (_limit + 1)
    LOOP
        cnt := cnt + 1;
        IF cnt = 1 THEN first_k := _keys; END IF;
        IF cnt <= _limit THEN acc := acc || _content; last_k := _keys; END IF;
    END LOOP;

    has_more := cnt > _limit;
    IF is_prev THEN
        acc := flip_jsonb_array(acc);
        fwd_first_k := last_k; fwd_last_k := first_k;
        next_present := (keyset IS NOT NULL);   -- a prev page always has the origin ahead
        prev_present := has_more;                -- ... and a further-back page iff more remain
    ELSE
        fwd_first_k := first_k; fwd_last_k := last_k;
        next_present := has_more;
        prev_present := (keyset IS NOT NULL);
    END IF;
    IF cnt > 0 AND next_present THEN next_tok := keyset_encode(fwd_last_k); END IF;
    IF cnt > 0 AND prev_present THEN prev_tok := keyset_encode(fwd_first_k); END IF;

    number_returned := jsonb_array_length(acc);

    IF next_tok IS NOT NULL THEN
        links := links || jsonb_build_object('rel', 'next', 'type', 'application/json',
            'method', 'GET', 'href', burl || '?token=next:' || next_tok);
    END IF;
    IF prev_tok IS NOT NULL THEN
        links := links || jsonb_build_object('rel', 'prev', 'type', 'application/json',
            'method', 'GET', 'href', burl || '?token=prev:' || prev_tok);
    END IF;

    RETURN jsonb_build_object(
        'collections', acc,
        'numberMatched', number_matched,
        'numberReturned', number_returned,
        'links', links
    );
END;
$$ LANGUAGE PLPGSQL STABLE PARALLEL SAFE;
-- END FRAGMENT: 004a_collectionsearch.sql

-- BEGIN FRAGMENT: 005_tileutils.sql
SET SEARCH_PATH TO pgstac, public;

CREATE OR REPLACE FUNCTION tileenvelope(zoom int, x int, y int) RETURNS geometry AS $$
WITH t AS (
    SELECT
        20037508.3427892 as merc_max,
        -20037508.3427892 as merc_min,
        (2 * 20037508.3427892) / (2 ^ zoom) as tile_size
)
SELECT st_makeenvelope(
    merc_min + (tile_size * x),
    merc_max - (tile_size * (y + 1)),
    merc_min + (tile_size * (x + 1)),
    merc_max - (tile_size * y),
    3857
) FROM t;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;DROP FUNCTION IF EXISTS mercgrid;


CREATE OR REPLACE FUNCTION ftime() RETURNS interval as $$
SELECT age(clock_timestamp(), transaction_timestamp());
$$ LANGUAGE SQL;
-- END FRAGMENT: 005_tileutils.sql

-- BEGIN FRAGMENT: 006_tilesearch.sql

-- geometrysearch: tile/area feature search. Walks the SAME next_band loop as search_page (server-side
-- adaptive cumulative-count bands over partition_bounds' unified per-month histogram) and hydrates the
-- SAME way (content_hydrate with the needs_fragment skip, json_agg, json output). It differs from
-- search_page only in its per-row action: a greedy coverage filter (st_intersection/union +
-- skipcovered/exitwhenfull) and the scan/limit/time budget that drives early exit. Rows that pass
-- coverage are collected and hydrated once at the end.
DROP FUNCTION IF EXISTS geometrysearch;
CREATE OR REPLACE FUNCTION geometrysearch(
    IN geom geometry,
    IN queryhash text,
    IN fields jsonb DEFAULT NULL,
    IN _scanlimit int DEFAULT 10000,
    IN _limit int DEFAULT 100,
    IN _timelimit interval DEFAULT '5 seconds'::interval,
    IN exitwhenfull boolean DEFAULT TRUE, -- Return as soon as the passed in geometry is fully covered
    IN skipcovered boolean DEFAULT TRUE   -- Skip any items that would show up completely under the previous items
) RETURNS json AS $$
DECLARE
    -- Same adaptive band sizing as search_page: first band ~one page (band_margin headroom), each
    -- subsequent band re-sized from the band's observed spatial hit-rate (band_safety headroom).
    band_margin CONSTANT numeric := 3.0;
    band_safety CONSTANT numeric := 1.5;
    band_cap_months CONSTANT int := 18;
    search searches%ROWTYPE;
    curs refcursor;
    _where text; query text; proj_expr text;
    iter_record items%ROWTYPE;
    page_rows items[] := '{}'::items[];   -- coverage-passing rows, hydrated once at the end
    features json;
    exit_flag boolean := FALSE;
    counter int := 1; scancounter int := 1; remaining_limit int := _scanlimit;
    tilearea float; unionedgeom geometry; clippedgeom geometry;
    unionedgeom_area float := 0; prev_area float := 0;
    _env pred_envelope; bnds record;
    lead_field text; eff_dir text; datetime_leading boolean; is_asc boolean; orderby_str text;
    cursor_idx int; mo interval := interval '1 month'; band record; band_target numeric; obs_sel numeric;
    band_fetched int; guard int := 0; cum_scanned bigint := 0;
BEGIN
    -- If the passed in geometry is not an area, coverage tests are meaningless.
    IF ST_GeometryType(geom) !~* 'polygon' THEN
        skipcovered := FALSE; exitwhenfull := FALSE;
    END IF;
    -- skipcovered implies exitwhenfull (once covered, nothing new can show through).
    IF skipcovered THEN exitwhenfull := TRUE; END IF;

    search := search_fromhash(queryhash);
    IF search IS NULL THEN
        RAISE EXCEPTION 'Search with Query Hash % Not Found', queryhash;
    END IF;

    tilearea := st_area(geom);
    _where := format('%s AND st_intersects(geometry, %L::geometry)', search._where, geom);

    -- Discovery envelope from the registered search AND the tile geometry, then the single
    -- partition_bounds read (unified per-month histogram) that next_band walks.
    _env := search_envelope(search.search);
    _env.geom := CASE
        WHEN _env.geom IS NULL THEN ST_Envelope(geom)
        ELSE ST_Envelope(ST_Intersection(_env.geom, ST_Envelope(geom)))
    END;
    SELECT * INTO bnds FROM partition_bounds(_env);

    -- Leading sort field/direction + the registered forward orderby. Bands are datetime windows walked
    -- newest-first unless the search sorts datetime ascending; within a band rows follow search.orderby.
    SELECT (array_agg(field ORDER BY ord))[1], (array_agg(dir ORDER BY ord))[1]
    INTO lead_field, eff_dir FROM keyset_sortkeys(search.search);
    datetime_leading := (lead_field = 'datetime');
    is_asc := (datetime_leading AND eff_dir = 'ASC');
    orderby_str := search.orderby;

    -- Per-row projection: skip the shared item_fragments lookup when the requested fields are
    -- satisfiable from item columns alone (needs_fragment, evaluated once for the whole query).
    IF needs_fragment(coalesce(fields, '{}'::jsonb), bnds.collections) THEN
        proj_expr := format('content_hydrate(i, %L::jsonb)', coalesce(fields, '{}'::jsonb));
    ELSE
        proj_expr := format('content_hydrate(i, %L::jsonb, true)', coalesce(fields, '{}'::jsonb));
    END IF;

    IF array_length(bnds.months, 1) IS NOT NULL THEN
        -- Walk bands in the SEARCH's datetime direction: newest month first for a descending search,
        -- oldest first when sorting datetime ascending. Mirrors search_page (004_search). Walking the
        -- wrong direction returns older items before newer ones for a descending limit/early-exit search,
        -- and (because band grouping shifts with the partition_stats histogram) makes the result depend on
        -- stats — a bug, since stats must only affect performance, never which rows come back.
        cursor_idx := CASE WHEN is_asc THEN 1 ELSE array_length(bnds.months, 1) END;
        band_target := (_limit + 1) * band_margin;
        <<bands>>
        WHILE NOT exit_flag AND guard < 80 LOOP
            guard := guard + 1;
            SELECT * INTO band FROM next_band(bnds.counts, cursor_idx, band_target, band_cap_months, NOT is_asc);
            -- process a valid band even when next_band also flags done; stop only on no band.
            EXIT bands WHEN band.band_start_idx IS NULL;
            query := format(
                'SELECT * FROM items i WHERE i.collection = ANY(%L::text[]) AND i.datetime >= %L AND i.datetime < %L AND %s ORDER BY %s LIMIT %L',
                bnds.collections, bnds.months[band.band_start_idx], bnds.months[band.band_end_idx] + mo, _where, orderby_str, remaining_limit);
            band_fetched := 0;
            OPEN curs FOR EXECUTE query;
            LOOP
                FETCH curs INTO iter_record;
                EXIT WHEN NOT FOUND;
                band_fetched := band_fetched + 1;
                IF exitwhenfull OR skipcovered THEN -- skip expensive geometry ops when neither is on
                    clippedgeom := st_intersection(geom, iter_record.geometry);
                    IF unionedgeom IS NULL THEN
                        unionedgeom := clippedgeom;
                    ELSE
                        unionedgeom := st_union(unionedgeom, clippedgeom);
                    END IF;
                    unionedgeom_area := st_area(unionedgeom);
                    IF skipcovered AND prev_area = unionedgeom_area THEN
                        scancounter := scancounter + 1;
                        CONTINUE;
                    END IF;
                    prev_area := unionedgeom_area;
                END IF;
                -- Collect the row; hydration happens once at the end (same content_hydrate path as search_page).
                page_rows := page_rows || iter_record;
                IF counter >= _limit
                    OR scancounter > _scanlimit
                    OR ftime() > _timelimit
                    OR (exitwhenfull AND unionedgeom_area >= tilearea)
                THEN
                    exit_flag := TRUE;
                    EXIT;
                END IF;
                counter := counter + 1;
                scancounter := scancounter + 1;
            END LOOP;
            CLOSE curs;
            cum_scanned := cum_scanned + band.scanned;
            cursor_idx := band.next_cursor_idx;
            EXIT bands WHEN exit_flag;
            -- LEARN: size the next band from this band's spatial hit-rate (fetched / rows scanned).
            obs_sel := GREATEST(band_fetched::numeric, 0.5) / GREATEST(cum_scanned, 1);
            band_target := ((_limit + 1 - counter) / obs_sel) * band_safety;
            remaining_limit := _scanlimit - scancounter;
        END LOOP;
    END IF;

    -- Hydrate the collected rows once (content_hydrate + needs_fragment skip, json output -- 1GB text
    -- ceiling, no 256MB jsonb-array limit), exactly like search_page.
    EXECUTE format('SELECT coalesce(json_agg(%s), ''[]''::json) FROM unnest($1::items[]) i', proj_expr)
    USING page_rows INTO features;

    RETURN json_build_object(
        'type', 'FeatureCollection',
        'features', coalesce(features, '[]'::json)
    );
END;
$$ LANGUAGE PLPGSQL;

DROP FUNCTION IF EXISTS geojsonsearch;
CREATE OR REPLACE FUNCTION geojsonsearch(
    IN geojson jsonb,
    IN queryhash text,
    IN fields jsonb DEFAULT NULL,
    IN _scanlimit int DEFAULT 10000,
    IN _limit int DEFAULT 100,
    IN _timelimit interval DEFAULT '5 seconds'::interval,
    IN exitwhenfull boolean DEFAULT TRUE,
    IN skipcovered boolean DEFAULT TRUE
) RETURNS json AS $$
    SELECT * FROM geometrysearch(
        st_geomfromgeojson(geojson),
        queryhash,
        fields,
        _scanlimit,
        _limit,
        _timelimit,
        exitwhenfull,
        skipcovered
    );
$$ LANGUAGE SQL;

DROP FUNCTION IF EXISTS xyzsearch;
CREATE OR REPLACE FUNCTION xyzsearch(
    IN _x int,
    IN _y int,
    IN _z int,
    IN queryhash text,
    IN fields jsonb DEFAULT NULL,
    IN _scanlimit int DEFAULT 10000,
    IN _limit int DEFAULT 100,
    IN _timelimit interval DEFAULT '5 seconds'::interval,
    IN exitwhenfull boolean DEFAULT TRUE,
    IN skipcovered boolean DEFAULT TRUE
) RETURNS json AS $$
    SELECT * FROM geometrysearch(
        st_transform(tileenvelope(_z, _x, _y), 4326),
        queryhash,
        fields,
        _scanlimit,
        _limit,
        _timelimit,
        exitwhenfull,
        skipcovered
    );
$$ LANGUAGE SQL;
-- END FRAGMENT: 006_tilesearch.sql

-- BEGIN FRAGMENT: 997_maintenance.sql

-- tighten_dirty_partition_stats: recompute the exact envelope + row count for dirty partitions (oldest
-- first), clearing dirty. Run off-hours (pg_cron or the maintenance CLI). Optional: a wide envelope only
-- over-includes a partition in search, so skipping it never loses rows. `_limit` caps the batch (NULL =
-- all dirty); returns the number of partitions tightened.
--
-- pg_cron example (operators install this themselves):
--   SELECT cron.schedule('pgstac-tighten', '*/15 * * * *',
--                        $$SELECT pgstac.tighten_dirty_partition_stats(200)$$);
CREATE OR REPLACE FUNCTION tighten_dirty_partition_stats(_limit int DEFAULT NULL)
RETURNS int AS $$
DECLARE
    _part text;
    _count int := 0;
BEGIN
    FOR _part IN
        SELECT partition FROM pgstac.partition_stats
        WHERE dirty
        ORDER BY last_updated NULLS FIRST
        LIMIT _limit
    LOOP
        PERFORM pgstac.tighten_partition_stats(_part);
        _count := _count + 1;
    END LOOP;
    RETURN _count;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;


CREATE OR REPLACE PROCEDURE analyze_items() AS $$
DECLARE
    q text;
    timeout_ts timestamptz;
BEGIN
    timeout_ts := statement_timestamp() + queue_timeout();
    WHILE clock_timestamp() < timeout_ts LOOP
        SELECT format('ANALYZE (VERBOSE, SKIP_LOCKED) %I;', relname) INTO q
        FROM pg_stat_user_tables
        WHERE relname like '_item%' AND (n_mod_since_analyze>0 OR last_analyze IS NULL) LIMIT 1;
        IF NOT FOUND THEN
            EXIT;
        END IF;
        RAISE NOTICE '%', q;
        EXECUTE q;
        COMMIT;
    END LOOP;
END;
$$ LANGUAGE PLPGSQL;


CREATE OR REPLACE PROCEDURE validate_constraints() AS $$
DECLARE
    q text;
BEGIN
    FOR q IN
    SELECT
        FORMAT(
            'ALTER TABLE %I.%I VALIDATE CONSTRAINT %I;',
            nsp.nspname,
            cls.relname,
            con.conname
        )

    FROM pg_constraint AS con
        JOIN pg_class AS cls
        ON con.conrelid = cls.oid
        JOIN pg_namespace AS nsp
        ON cls.relnamespace = nsp.oid
    WHERE convalidated = FALSE AND contype in ('c','f')
    AND nsp.nspname = 'pgstac'
    LOOP
        RAISE NOTICE '%', q;
        PERFORM run_or_queue(q);
        COMMIT;
    END LOOP;
END;
$$ LANGUAGE PLPGSQL;


CREATE OR REPLACE FUNCTION collection_extent(_collection text, runupdate boolean default false) RETURNS jsonb AS $$
DECLARE
    geom_extent geometry;
    mind timestamptz;
    maxd timestamptz;
    extent jsonb;
BEGIN
    IF runupdate THEN
        PERFORM tighten_partition_stats(partition)
        FROM partitions_view WHERE collection=_collection;
    END IF;
    SELECT
        min(lower(dtrange)),
        max(upper(edtrange)),
        st_extent(spatial)
    INTO
        mind,
        maxd,
        geom_extent
    FROM partitions_view
    WHERE collection=_collection;

    IF geom_extent IS NOT NULL AND mind IS NOT NULL AND maxd IS NOT NULL THEN
        extent := jsonb_build_object(
                'spatial', jsonb_build_object(
                    'bbox', to_jsonb(array[array[st_xmin(geom_extent), st_ymin(geom_extent), st_xmax(geom_extent), st_ymax(geom_extent)]])
                ),
                'temporal', jsonb_build_object(
                    'interval', to_jsonb(array[array[mind, maxd]])
                )
        );
        RETURN extent;
    END IF;
    RETURN NULL;
END;
$$ LANGUAGE PLPGSQL;

CREATE OR REPLACE FUNCTION gc_deleted_items_log_batch(
    retention_interval interval DEFAULT '30 days',
    batch_limit integer DEFAULT 10000
) RETURNS bigint AS $$
DECLARE
    batch_deleted bigint;
BEGIN
    WITH to_delete AS (
        SELECT ctid
        FROM items_deleted_log
        WHERE deleted_at < now() - retention_interval
        ORDER BY deleted_at
        LIMIT GREATEST(COALESCE(batch_limit, 10000), 1)
    ),
    deleted AS (
        DELETE FROM items_deleted_log d
        USING to_delete td
        WHERE d.ctid = td.ctid
        RETURNING 1
    )
    SELECT count(*)::bigint INTO batch_deleted FROM deleted;

    RETURN batch_deleted;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION gc_deleted_items_log(
    retention_interval interval,
    batch_limit integer
) RETURNS bigint AS $$
DECLARE
    deleted_count bigint := 0;
    batch_deleted bigint;
BEGIN
    LOOP
        batch_deleted := gc_deleted_items_log_batch(retention_interval, batch_limit);
        deleted_count := deleted_count + batch_deleted;
        EXIT WHEN batch_deleted = 0;
    END LOOP;

    RETURN deleted_count;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION gc_deleted_items_log(retention_interval interval DEFAULT '30 days') RETURNS bigint AS $$
    SELECT gc_deleted_items_log(retention_interval, 10000);
$$ LANGUAGE SQL SECURITY DEFINER;

CREATE OR REPLACE PROCEDURE gc_deleted_items_log_committed(
    retention_interval interval DEFAULT '30 days',
    batch_limit integer DEFAULT 10000
) AS $$
DECLARE
    batch_deleted bigint;
BEGIN
    LOOP
        batch_deleted := gc_deleted_items_log_batch(retention_interval, batch_limit);
        EXIT WHEN batch_deleted = 0;
        COMMIT;
    END LOOP;
END;
$$ LANGUAGE PLPGSQL;


-- update_collection_extents: recompute every collection's extent from partitions_view.
CREATE OR REPLACE FUNCTION update_collection_extents() RETURNS VOID AS $$
UPDATE collections
    SET content = jsonb_set_lax(
        content,
        '{extent}'::text[],
        collection_extent(id, FALSE),
        true,
        'use_json_null'
    )
;
$$ LANGUAGE SQL;


-- ---------------------------------------------------------------------------
-- Field registry maintenance: track which paths (and value types) exist per
-- collection. Used for schema inference (e.g. the geoparquet export schema).
-- jsonb_field_rows is in 001a_jsonutils.sql.
-- ---------------------------------------------------------------------------

-- update_field_registry_from_sample: UPSERT registry rows from an array of raw item content JSONBs (the
-- caller picks the sample); value_kinds accumulate observed types over time.
CREATE OR REPLACE FUNCTION update_field_registry_from_sample(
    _collection text,
    item_contents jsonb[]
) RETURNS void AS $$
    INSERT INTO item_field_registry (collection, path, is_leaf, value_kinds, first_seen, last_seen)
    SELECT
        _collection,
        r.path,
        bool_and(r.is_leaf)                                                       AS is_leaf,
        array_agg(DISTINCT r.value_kind) FILTER (WHERE r.value_kind IS NOT NULL)  AS value_kinds,
        now(),
        now()
    FROM unnest(item_contents) AS item(content)
    CROSS JOIN LATERAL jsonb_field_rows(item.content) AS r(path, is_leaf, value_kind)
    GROUP BY r.path
    ON CONFLICT (collection, path) DO UPDATE SET
        is_leaf     = EXCLUDED.is_leaf,
        value_kinds = (
            SELECT array_agg(DISTINCT v)
            FROM unnest(item_field_registry.value_kinds || EXCLUDED.value_kinds) t(v)
        ),
        last_seen   = now()
    ;
$$ LANGUAGE SQL VOLATILE SECURITY DEFINER;


-- update_field_registry_from_items: sample a live collection and UPSERT registry rows (TABLESAMPLE
-- BERNOULLI(5) above ~10k rows by pg_class estimate, else LIMIT 1000). Returns (registered_paths,
-- rows_processed).
CREATE OR REPLACE FUNCTION update_field_registry_from_items(
    _collection text
) RETURNS TABLE (registered_paths int, rows_processed int) AS $$
DECLARE
    est_rows bigint;
    nrows    int;
    npaths   int;
BEGIN
    -- Sum reltuples across the registered item partitions for this collection.
    -- reltuples can be -1 (never analyzed); treat negative values as zero.
    SELECT COALESCE(sum(GREATEST(c.reltuples::bigint, 0)), 0) INTO est_rows
    FROM partitions_view p
    JOIN pg_class c ON c.relname = p.partition
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE p.collection = _collection
      AND n.nspname = 'pgstac'
      AND c.relkind = 'r';

    IF est_rows > 10000 THEN
        -- Large collection: use statistical sampling to avoid full seq-scan.
        WITH sampled AS (
            SELECT content_hydrate(i) AS content FROM items i TABLESAMPLE BERNOULLI(5) WHERE i.collection = _collection
        ),
        upserted AS (
            INSERT INTO item_field_registry (collection, path, is_leaf, value_kinds, first_seen, last_seen)
            SELECT
                _collection,
                r.path,
                bool_and(r.is_leaf)                                                       AS is_leaf,
                array_agg(DISTINCT r.value_kind) FILTER (WHERE r.value_kind IS NOT NULL)  AS value_kinds,
                now(), now()
            FROM sampled
            CROSS JOIN LATERAL jsonb_field_rows(content) AS r(path, is_leaf, value_kind)
            GROUP BY r.path
            ON CONFLICT (collection, path) DO UPDATE SET
                is_leaf     = EXCLUDED.is_leaf,
                value_kinds = (
                    SELECT array_agg(DISTINCT v)
                    FROM unnest(item_field_registry.value_kinds || EXCLUDED.value_kinds) t(v)
                ),
                last_seen   = now()
            RETURNING 1
        )
        SELECT
            (SELECT count(*)::int FROM upserted),
            (SELECT count(*)::int FROM sampled)
        INTO npaths, nrows;
    ELSE
        -- Small collection: process up to 1000 rows to avoid BERNOULLI returning 0 rows.
        WITH sampled AS (
            SELECT content_hydrate(i) AS content FROM items i WHERE i.collection = _collection LIMIT 1000
        ),
        upserted AS (
            INSERT INTO item_field_registry (collection, path, is_leaf, value_kinds, first_seen, last_seen)
            SELECT
                _collection,
                r.path,
                bool_and(r.is_leaf)                                                       AS is_leaf,
                array_agg(DISTINCT r.value_kind) FILTER (WHERE r.value_kind IS NOT NULL)  AS value_kinds,
                now(), now()
            FROM sampled
            CROSS JOIN LATERAL jsonb_field_rows(content) AS r(path, is_leaf, value_kind)
            GROUP BY r.path
            ON CONFLICT (collection, path) DO UPDATE SET
                is_leaf     = EXCLUDED.is_leaf,
                value_kinds = (
                    SELECT array_agg(DISTINCT v)
                    FROM unnest(item_field_registry.value_kinds || EXCLUDED.value_kinds) t(v)
                ),
                last_seen   = now()
            RETURNING 1
        )
        SELECT
            (SELECT count(*)::int FROM upserted),
            (SELECT count(*)::int FROM sampled)
        INTO npaths, nrows;
    END IF;

    RETURN QUERY SELECT npaths, nrows;
END;
$$ LANGUAGE PLPGSQL VOLATILE SECURITY DEFINER;


-- refresh_field_registry: expire registry entries not seen within retention_interval (scheduled
-- maintenance). Returns (collection, expired_paths) per affected collection.
CREATE OR REPLACE FUNCTION refresh_field_registry(
    _collection text DEFAULT NULL,
    retention_interval interval DEFAULT '90 days'
) RETURNS TABLE (collection_id text, expired_paths int) AS $$
    WITH deleted AS (
        DELETE FROM item_field_registry
        WHERE (_collection IS NULL OR collection = _collection)
          AND last_seen < now() - retention_interval
        RETURNING collection
    )
    SELECT collection, count(*)::int
    FROM deleted
    GROUP BY collection;
$$ LANGUAGE SQL VOLATILE SECURITY DEFINER;


-- gc_fragments: garbage-collect orphaned item_fragments with a single set-based DELETE (NOT EXISTS
-- anti-join against items.fragment_id). items.fragment_id has no FK (partitioned-items incremental
-- NOT VALID FKs aren't supported), so a fragment unreferenced at the DELETE snapshot but referenced by a
-- concurrent insert can be removed; the retention_interval guard makes this unlikely. Run during
-- low-ingest periods.
CREATE OR REPLACE FUNCTION gc_fragments(
    _collection text DEFAULT NULL,
    retention_interval interval DEFAULT '90 days'
) RETURNS TABLE (
    collection_id text,
    fragments_removed int
) AS $$
    WITH deleted AS (
        DELETE FROM item_fragments f
        WHERE
            (_collection IS NULL OR f.collection = _collection)
            AND f.created_at < now() - retention_interval
            AND NOT EXISTS (SELECT 1 FROM items i WHERE i.fragment_id = f.id)
        RETURNING f.collection
    )
    SELECT collection, count(*)::int
    FROM deleted
    GROUP BY collection;
$$ LANGUAGE SQL VOLATILE PARALLEL UNSAFE SECURITY DEFINER;


-- tighten_partition_stats: recompute the exact envelope (datetime/end_datetime min-max + spatial extent)
-- and row count for one partition, then clear `dirty`. The only function that narrows a partition_stats
-- envelope; the maintenance sweeps drive it over partition_stats WHERE dirty. An empty partition tightens
-- to an 'empty' range so search prunes it out.
CREATE OR REPLACE FUNCTION tighten_partition_stats(_partition text) RETURNS void AS $$
DECLARE
    _n bigint;
    _dtmin timestamptz; _dtmax timestamptz;
    _edtmin timestamptz; _edtmax timestamptz;
    _spatial geometry;
    _dtrange tstzrange;
    _edtrange tstzrange;
    _collection text;
BEGIN
    -- Hold the partition's advisory lock across the scan + write: tighten narrows dtrange to the scanned
    -- extent and clears dirty, so without the lock a concurrent ingest committing a row outside that
    -- extent would be left uncovered (search would prune + miss it). Same lock check_partition uses, so
    -- tighten serializes with ingest into this partition only.
    PERFORM pg_advisory_xact_lock(hashtext('pgstac.check_partition'), hashtext(_partition));

    EXECUTE format(
        $q$
            SELECT count(*), min(datetime), max(datetime), min(end_datetime), max(end_datetime),
                   st_setsrid(st_extent(geometry)::geometry, 4326)
            FROM %I
        $q$,
        _partition
    ) INTO _n, _dtmin, _dtmax, _edtmin, _edtmax, _spatial;

    IF _n = 0 THEN
        _dtrange := 'empty'::tstzrange;
        _edtrange := 'empty'::tstzrange;
        _spatial := NULL;
    ELSE
        _dtrange := tstzrange(_dtmin, _dtmax, '[]');
        _edtrange := tstzrange(_edtmin, _edtmax, '[]');
    END IF;

    SELECT pv.collection
        INTO _collection
    FROM partitions_view pv WHERE partition = _partition;

    INSERT INTO partition_stats
        (partition, collection, dtrange, edtrange, spatial, n, dirty, last_updated)
        VALUES (_partition, _collection, _dtrange, _edtrange, _spatial, _n, false, now())
        ON CONFLICT (partition) DO UPDATE SET
            collection = EXCLUDED.collection,
            dtrange = EXCLUDED.dtrange,
            edtrange = EXCLUDED.edtrange,
            spatial = EXCLUDED.spatial,
            n = EXCLUDED.n,
            dirty = false,
            last_updated = now();
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;
-- END FRAGMENT: 997_maintenance.sql

